<!-- Hero Section with Parallax Effect -->
<section class="page-hero" style="
    background: url('./assets/img/NewTemp/bull.jpg');
    background-size: cover;
    background-position: center;
    background-attachment: fixed;
    min-height: 50vh;
    display: flex;
    align-items: center;
    justify-content: center;
    text-align: center;
    position: relative;
    overflow: hidden;
">
    <!-- Dynamic Gradient Overlay -->
    <div style="
        position: absolute;
        top: 0;
        left: 0;
        right: 0;
        bottom: 0;
        /* background: linear-gradient(135deg, rgba(30, 77, 130, 0.92) 0%, rgba(230, 26, 56, 0.90) 50%,  rgba(211, 146, 102, 0.88) 100%); */
        /* background: linear-gradient(
  135deg,
  rgba(30, 77, 130, 0.92) 0%, 
  rgba(217, 149, 102, 0.94) 50%, 
  rgba(211, 146, 102, 0.88) 100%
); */
background: linear-gradient(
  135deg,
  rgba(30, 77, 130, 0.75) 0%, 
  rgba(217, 149, 102, 0.65) 50%, 
  rgba(211, 146, 102, 0.55) 100%
);


        background-size: 200% 200%;
        animation: gradientFlow 5s ease infinite;
    "></div>
    
    <!-- Floating Orbs -->
    <div style="
        position: absolute;
        width: 400px;
        height: 400px;
        background: radial-gradient(circle, rgba(255, 140, 0, 0.3), transparent);
        border-radius: 50%;
        top: -100px;
        right: -100px;
        animation: float 20s ease-in-out infinite;
    "></div>
    
    <div style="
        position: absolute;
        width: 300px;
        height: 300px;
        background: radial-gradient(circle, rgba(211, 146, 102, 0.25), transparent);
        border-radius: 50%;
        bottom: -80px;
        left: -80px;
        animation: float 15s ease-in-out infinite reverse;
    "></div>
    
    <div class="container" style="position: relative; z-index: 3;">
        <div style="opacity: 0; animation: fadeInUp 1s ease forwards; animation-delay: 0.2s;">
            <h1 style="
                color: white;
                font-size: clamp(36px, 6vw, 68px);
                font-weight: 800;
                text-shadow: 0 10px 30px rgba(0,0,0,0.3);
                margin: 0 0 20px 0;
                letter-spacing: -1px;
                line-height: 1.1;
            ">
                Trading Platforms
            </h1>
            
            <!-- Modern Accent Line -->
            <div style="
                height: 3px;
                width: 100px;
                background: linear-gradient(90deg, transparent, #e61a38, #d39266, transparent);
                margin: 0 auto;
                border-radius: 3px;
                box-shadow: 0 0 20px rgba(255, 140, 0, 0.5);
            "></div>
        </div>
    </div>
    
    <!-- Scroll Indicator -->
    <div style="
        position: absolute;
        bottom: 30px;
        left: 50%;
        transform: translateX(-50%);
        z-index: 3;
        opacity: 0;
        animation: fadeIn 1s ease forwards 1.5s;
    ">
        <div style="
            width: 30px;
            height: 40px;
            border: 2px solid rgba(255, 255, 255, 0.5);
            border-radius: 20px;
            position: relative;
        ">
            <div style="
                width: 6px;
                height: 10px;
                background: white;
                border-radius: 3px;
                position: absolute;
                top: 8px;
                left: 50%;
                transform: translateX(-50%);
                animation: scrollDown 2s ease infinite;
            "></div>
        </div>
    </div>
</section>




